esqlQuery.esql:
TS metrics-kubeletstatsreceiver.otel-*, metrics-k8sclusterreceiver.otel-*
| WHERE k8s.node.name IS NOT NULL
    AND (k8s.node.cpu.usage IS NOT NULL OR k8s.node.allocatable_cpu IS NOT NULL)
| STATS avg_cpu = AVG(k8s.node.cpu.usage),
    allocatable_cpu = MAX(k8s.node.allocatable_cpu)
    BY k8s.node.name
| EVAL cpu_utilization = avg_cpu / allocatable_cpu
// Alert when average CPU usage exceeds 90% of allocatable capacity.
// Adjust the threshold to suit your environment.
//
// Requires k8s.node.allocatable_cpu from k8sclusterreceiver.
// This metric is controlled by allocatable_types_to_report config
// option, which must include "cpu". Not enabled by default.
// If unavailable, replace the utilization check with a static
// threshold on avg_cpu, e.g.: WHERE avg_cpu > 3.6
| WHERE cpu_utilization > 0.9
| KEEP k8s.node.name, avg_cpu, allocatable_cpu, cpu_utilization
